namespace sv_0b580b7897ea465490762961ce850610.Models;

public enum Severity
{
    Info,
    Warning,
    Critical
}

public class Notification
{
    public Guid Id { get; set; } = Guid.NewGuid();
    public string Title { get; set; } = string.Empty;
    public string Message { get; set; } = string.Empty;
    public Severity Severity { get; set; }
    public bool IsRead { get; set; }
    public DateTime Timestamp { get; set; } = DateTime.UtcNow;
}

using sv_0b580b7897ea465490762961ce850610.Models;

namespace sv_0b580b7897ea465490762961ce850610.Services;

/// <summary>
/// Scoped per circuit. Holds notification state and notifies all subscribed
/// components when any mutation occurs via an event.
/// </summary>
public class NotificationHub
{
    private readonly List<Notification> _notifications = new();
    private readonly object _lock = new();

    /// <summary>
    /// Subscribers attach delegates here. Each delegate is expected to call
    /// InvokeAsync(StateHasChanged) so it marshals back to the correct
    /// synchronization context.
    /// </summary>
    public event Func<Task>? OnChange;

    public IReadOnlyList<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.OrderByDescending(n => n.Timestamp).ToList();
        }
    }

    public int GetUnreadCount()
    {
        lock (_lock)
        {
            return _notifications.Count(n => !n.IsRead);
        }
    }

    public async Task AddNotification(string title, string message, Severity severity)
    {
        lock (_lock)
        {
            _notifications.Add(new Notification
            {
                Title = title,
                Message = message,
                Severity = severity
            });
        }

        await NotifySubscribers();
    }

    public async Task MarkAsRead(Guid id)
    {
        lock (_lock)
        {
            var item = _notifications.FirstOrDefault(n => n.Id == id);
            if (item is not null)
                item.IsRead = true;
        }

        await NotifySubscribers();
    }

    public async Task MarkAllRead()
    {
        lock (_lock)
        {
            foreach (var n in _notifications)
                n.IsRead = true;
        }

        await NotifySubscribers();
    }

    public async Task DismissNotification(Guid id)
    {
        lock (_lock)
        {
            _notifications.RemoveAll(n => n.Id == id);
        }

        await NotifySubscribers();
    }

    private async Task NotifySubscribers()
    {
        if (OnChange is not null)
        {
            // Invoke every subscriber. Each one is responsible for marshalling
            // to its own sync context via InvokeAsync.
            foreach (var handler in OnChange.GetInvocationList().Cast<Func<Task>>())
            {
                await handler.Invoke();
            }
        }
    }
}

using sv_0b580b7897ea465490762961ce850610.Models;

namespace sv_0b580b7897ea465490762961ce850610.Services;

/// <summary>
/// Scoped service activated on the Dashboard page. Fires a random
/// notification every 15 seconds on a background thread. The component
/// that owns it must call Start/Stop and is responsible for disposal.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private static readonly (string Title, string Message, Severity Severity)[] Templates =
    [
        ("Disk Usage High",      "Disk usage on /dev/sda1 exceeded 90%.",  Severity.Critical),
        ("CPU Spike Detected",   "CPU usage exceeded 95% for 30 seconds.", Severity.Critical),
        ("Build Succeeded",      "CI pipeline #4821 completed.",           Severity.Info),
        ("Deployment Pending",   "Release v3.2.1 is awaiting approval.",   Severity.Warning),
        ("New User Signup",      "A new user registered on the platform.", Severity.Info),
        ("SSL Cert Expiring",    "Certificate for *.example.com expires in 7 days.", Severity.Warning),
        ("Memory Leak Suspected","Service 'orders-api' memory growing.",   Severity.Critical),
        ("Backup Completed",     "Nightly backup finished successfully.",  Severity.Info),
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        if (_cts is not null) return; // already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(15));

        _ = RunAsync(_cts.Token);
    }

    private async Task RunAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                var template = Templates[Random.Shared.Next(Templates.Length)];
                await _hub.AddNotification(template.Title, template.Message, template.Severity);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose
        }
    }

    public void Stop()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        _cts = null;
        _timer = null;
    }

    public void Dispose()
    {
        Stop();
    }
}

