@rendermode InteractiveServer
@implements IDisposable
@inject NotificationHub Hub

<div class="notification-bell position-relative d-inline-block px-3 py-2" style="cursor:pointer;">
    <a href="notifications" class="text-white text-decoration-none">
        <span class="bi bi-bell-fill" aria-hidden="true">🔔</span>
        @if (_unreadCount > 0)
        {
            <span class="badge bg-danger rounded-pill position-absolute top-0 start-100 translate-middle">
                @_unreadCount
            </span>
        }
    </a>
</div>

@code {
    private int _unreadCount;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        Hub.OnChange += OnHubChanged;
    }

    private async Task OnHubChanged()
    {
        _unreadCount = Hub.GetUnreadCount();
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationHub Hub

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<div class="mb-3">
    <button class="btn btn-outline-primary" @onclick="MarkAllRead" disabled="@(_unreadCount == 0)">
        Mark All Read (@_unreadCount unread)
    </button>
</div>

@if (!_notifications.Any())
{
    <div class="alert alert-secondary">No notifications yet.</div>
}
else
{
    @foreach (var group in _grouped)
    {
        <h4 class="mt-4">
            <span class="badge @SeverityBadgeClass(group.Key)">@group.Key</span>
        </h4>
        <div class="list-group mb-3">
            @foreach (var n in group)
            {
                <div class="list-group-item @(n.IsRead ? "" : "list-group-item-warning")">
                    <div class="d-flex w-100 justify-content-between">
                        <h5 class="mb-1">
                            @if (!n.IsRead) { <strong>●</strong> }
                            @n.Title
                        </h5>
                        <small>@n.Timestamp.ToString("g")</small>
                    </div>
                    <p class="mb-1">@n.Message</p>
                    <div>
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-sm btn-outline-success me-2"
                                    @onclick="() => MarkRead(n.Id)">Mark Read</button>
                        }
                        <button class="btn btn-sm btn-outline-danger"
                                @onclick="() => Dismiss(n.Id)">Dismiss</button>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    private IReadOnlyList<Notification> _notifications = [];
    private IEnumerable<IGrouping<Severity, Notification>> _grouped = [];
    private int _unreadCount;

    protected override void OnInitialized()
    {
        RefreshData();
        Hub.OnChange += OnHubChanged;
    }

    private void RefreshData()
    {
        _notifications = Hub.GetAll();
        _unreadCount = Hub.GetUnreadCount();
        // Group by severity, Critical first
        _grouped = _notifications
            .GroupBy(n => n.Severity)
            .OrderByDescending(g => g.Key);
    }

    private async Task OnHubChanged()
    {
        RefreshData();
        await InvokeAsync(StateHasChanged);
    }

    private async Task MarkRead(Guid id) => await Hub.MarkAsRead(id);
    private async Task MarkAllRead() => await Hub.MarkAllRead();
    private async Task Dismiss(Guid id) => await Hub.DismissNotification(id);

    private static string SeverityBadgeClass(Severity s) => s switch
    {
        Severity.Critical => "bg-danger",
        Severity.Warning  => "bg-warning text-dark",
        _                 => "bg-info text-dark"
    };

    public void Dispose()
    {
        Hub.OnChange -= OnHubChanged;
    }
}

